// openclaw-privacy-router plugin
import { defineProvider } from 'openclaw/plugin-sdk';

export default defineProvider({
  name: 'privacy-router',
  baseUrl: 'http://localhost:8787/v1',
  api: 'openai-completions',
  transforms: {
    input: async (text) => {
      // Pipeline runs server-side, no client transform needed
      return text;
    },
    output: async (text) => {
      // Hydration also runs server-side
      return text;
    }
  }
});
